javascript:(function () { 'use strict'; const m = location.pathname.match(/\/scenarios\/([a-f0-9]{24})/i); if (!m) { alert('⚠️ uzustudio のシナリオ編集ページで実行してください。\n\n例: editor.studio.uzu-app.com/ja/scenarios/.../edit/characters'); return; } const scenarioId = m[1]; const origin = location.origin; const API_PATHS = [ `/api/scenarios/${scenarioId}`, `/api/v1/scenarios/${scenarioId}`, `/api/scenarios/${scenarioId}/characters`, `/api/scenarios/${scenarioId}/phases`, `/api/scenarios/${scenarioId}/clues`, `/api/scenarios/${scenarioId}/tokens`, `/api/scenarios/${scenarioId}/rooms`, `/api/scenarios/${scenarioId}/actions`, `/api/scenarios/${scenarioId}/epilogues`, `/api/scenarios/${scenarioId}/scripts`, `/api/scenarios/${scenarioId}/lines`, ]; const TEXT_KEYS = new Set([ 'text', 'body', 'content', 'description', 'name', 'title', 'dialogue', 'narration', 'message', 'script', 'caption', 'label', 'hint', 'flavor', 'note', 'memo', 'detail', 'displayname', 'charactername', 'linetext', 'talktext', 'flavortext', 'profile', 'summary', 'objective', 'prologue', 'epilogue', 'kana', 'ruby', 'condition', ]); const SKIP_RE = /^(true|false|null|\d+|[a-f0-9]{24}|#[0-9a-f]{3,8}|https?:\/\/.+)$/i; function isMeaningful(s) { if (typeof s !== 'string') return false; s = s.trim(); if (s.length < 2) return false; if (SKIP_RE.test(s)) return false; if (/^[a-zA-Z0-9_\-]+$/.test(s) && s.length < 20) return false; return true; } function collectText(obj, out) { if (typeof obj === 'string') { if (isMeaningful(obj)) out.push(obj.trim()); } else if (Array.isArray(obj)) { obj.forEach(v => collectText(v, out)); } else if (obj && typeof obj === 'object') { for (const [k, v] of Object.entries(obj)) { if (TEXT_KEYS.has(k.toLowerCase())) { collectText(v, out); } else { collectText(v, out); } } } } function guessSection(url) { const map = { characters: 'キャラクター', phases: 'フェーズ', clues: '手がかり', tokens: 'トークン', rooms: '部屋', actions: 'アクション', epilogues: 'エピローグ', prologue: 'プロローグ', scripts: '台本', lines: 'セリフ', }; for (const [k, v] of Object.entries(map)) { if (url.includes(k)) return v; } return 'シナリオ'; } const overlay = document.createElement('div'); overlay.style.cssText = [ 'position:fixed', 'top:0', 'left:0', 'width:100%', 'height:100%', 'background:rgba(0,0,0,.65)', 'display:flex', 'flex-direction:column', 'align-items:center', 'justify-content:center', 'z-index:999999', 'font-family:sans-serif', ].join(';'); overlay.innerHTML = ` <div style="background:#fff;border-radius:12px;padding:28px 32px;max-width:340px;width:90%;text-align:center"> <div style="font-size:22px;margin-bottom:8px">📖 文章を抽出中...</div> <div id="uzuStatus" style="color:#555;font-size:13px;margin-bottom:14px">準備中</div> <div style="background:#eee;border-radius:6px;height:8px;overflow:hidden"> <div id="uzuBar" style="background:#6c63ff;height:100%;width:0%;transition:width .3s"></div> </div> </div>`; document.body.appendChild(overlay); const statusEl = document.getElementById('uzuStatus'); const barEl = document.getElementById('uzuBar'); function setProgress(pct, msg) { barEl.style.width = pct + '%'; statusEl.textContent = msg; } async function run() { const results = {}; const total = API_PATHS.length; for (let i = 0; i < API_PATHS.length; i++) { const path = API_PATHS[i]; const url = origin + path; const pct = Math.round(((i + 1) / total) * 80); setProgress(pct, `取得中... (${i + 1}/${total})`); try { const res = await fetch(url, { headers: { 'Accept': 'application/json' }, credentials: 'include', }); if (res.ok) { const json = await res.json(); results[url] = json; } } catch (_) { } } setProgress(85, 'テキスト整理中...'); const sectionMap = {}; for (const [url, body] of Object.entries(results)) { const section = guessSection(url); const texts = []; collectText(body, texts); if (!sectionMap[section]) sectionMap[section] = []; sectionMap[section].push(...texts); } const lines = [`# シナリオ: ${scenarioId}`, '']; for (const [section, texts] of Object.entries(sectionMap)) { const unique = [...new Set(texts)]; if (!unique.length) continue; lines.push(`## ${section}`); lines.push(...unique); lines.push(''); } const totalCount = lines.filter(l => l && !l.startsWith('#')).length; setProgress(95, 'ダウンロード準備中...'); const blob = new Blob([lines.join('\n')], { type: 'text/plain;charset=utf-8' }); const blobUrl = URL.createObjectURL(blob); const a = document.createElement('a'); a.href = blobUrl; a.download = `scenario_${scenarioId}.txt`; document.body.appendChild(a); a.click(); document.body.removeChild(a); setTimeout(() => URL.revokeObjectURL(blobUrl), 5000); setProgress(100, `完了！ ${totalCount} 件のテキストを抽出しました`); setTimeout(() => overlay.remove(), 3000); } run().catch(err => { overlay.remove(); alert('エラーが発生しました: ' + err.message); }); })();